/**
 * Path change request object with a new path.
 *
 * @property {string} path Absolute path
 * @property {string} pathWithoutBasePath Subpath that does not contain the app base path. Depending on the app routing library, it may be required to use this parameter when passing it to the router.
 * @ignore
 */
export interface PathChangeRequest {
    path: string;
    pathWithoutBasePath: string;
}
